-- =============================================================================
-- Script: import_exam_session_subjects.sql
-- Purpose: Import exam session-subject associations into
--          acted.catalog_exam_session_subjects by looking up IDs from
--          acted.catalog_exam_sessions and acted.catalog_subjects.
-- Database: PostgreSQL (acted schema)
--
-- Prerequisites:
--   - Run import_exam_sessions.sql first (populates exam sessions)
--   - Run import_subjects.sql first (populates subjects)
--
-- Usage:
--   \i import_exam_session_subjects.sql
--
-- Notes:
--   - Session codes are trimmed of leading/trailing whitespace
--   - Unmatched session codes or subject codes are reported as warnings
--   - Duplicate (exam_session, subject) pairs are skipped via unique constraint
--   - Session code '98' maps to two exam sessions; both get the subjects
-- =============================================================================

\set ON_ERROR_STOP on
\timing on

