    GET DIAGNOSTICS v_staged = ROW_COUNT;
    RAISE NOTICE 'Staged % rows in temp table', v_staged;

    -- =========================================================================
    -- Stage 2: Report orphan session codes (in CSV but not in exam_sessions)
    -- =========================================================================
    SELECT COUNT(DISTINCT t.session_code) INTO v_orphan_sessions
    FROM tmp_ess t
    WHERE NOT EXISTS (
        SELECT 1 FROM "acted"."catalog_exam_sessions" es
        WHERE es.session_code = t.session_code
    );

    IF v_orphan_sessions > 0 THEN
        RAISE NOTICE '';
        RAISE NOTICE 'WARNING: % session code(s) not found in catalog_exam_sessions:', v_orphan_sessions;
        FOR rec IN
            SELECT DISTINCT t.session_code, COUNT(*) AS subject_count
            FROM tmp_ess t
            WHERE NOT EXISTS (
                SELECT 1 FROM "acted"."catalog_exam_sessions" es
                WHERE es.session_code = t.session_code
            )
            GROUP BY t.session_code
            ORDER BY t.session_code
        LOOP
            RAISE NOTICE '  - session_code "%" (% subjects skipped)', rec.session_code, rec.subject_count;
        END LOOP;
    END IF;

    -- =========================================================================
    -- Stage 3: Report orphan subject codes (in CSV but not in subjects)
    -- =========================================================================
    SELECT COUNT(DISTINCT t.subject_code) INTO v_orphan_subjects
    FROM tmp_ess t
    WHERE NOT EXISTS (
        SELECT 1 FROM "acted"."catalog_subjects" s
        WHERE s.code = t.subject_code
    );

    IF v_orphan_subjects > 0 THEN
        RAISE NOTICE '';
        RAISE NOTICE 'WARNING: % subject code(s) not found in catalog_subjects:', v_orphan_subjects;
        FOR rec IN
            SELECT DISTINCT t.subject_code
            FROM tmp_ess t
            WHERE NOT EXISTS (
                SELECT 1 FROM "acted"."catalog_subjects" s
                WHERE s.code = t.subject_code
            )
            ORDER BY t.subject_code
        LOOP
            RAISE NOTICE '  - subject_code "%"', rec.subject_code;
        END LOOP;
    END IF;

    -- =========================================================================
    -- Stage 4: Insert into catalog_exam_session_subjects via ID lookup
    -- =========================================================================
    SELECT COUNT(*) INTO v_before FROM "acted"."catalog_exam_session_subjects";

    INSERT INTO "acted"."catalog_exam_session_subjects" (
        exam_session_id,
        subject_id,
        is_active,
        created_at,
        updated_at
    )
    SELECT DISTINCT
        es.id,
        s.id,
        TRUE,
        NOW(),
        NOW()
    FROM tmp_ess t
    JOIN "acted"."catalog_exam_sessions" es ON es.session_code = t.session_code
    JOIN "acted"."catalog_subjects" s ON s.code = t.subject_code
    ON CONFLICT (exam_session_id, subject_id) DO NOTHING;

    SELECT COUNT(*) INTO v_after FROM "acted"."catalog_exam_session_subjects";
    v_inserted := v_after - v_before;

    -- =========================================================================
    -- Summary
    -- =========================================================================
    RAISE NOTICE '';
    RAISE NOTICE '=========================================================================';
    RAISE NOTICE 'IMPORT COMPLETE';
    RAISE NOTICE '  Rows staged from CSV: %', v_staged;
    RAISE NOTICE '  Rows inserted: %', v_inserted;
    RAISE NOTICE '  Rows skipped (already exist or orphan): %', v_staged - v_inserted;
    RAISE NOTICE '  Orphan session codes: %', v_orphan_sessions;
    RAISE NOTICE '  Orphan subject codes: %', v_orphan_subjects;
    RAISE NOTICE '  Total rows in table: %', v_after;
    RAISE NOTICE '=========================================================================';

END $$;

COMMIT;

-- =============================================================================
-- Verification: Summary by session
-- =============================================================================
\echo ''
\echo '--- Verification: Subject count per exam session ---'

SELECT es.session_code, COUNT(*) AS subject_count
FROM "acted"."catalog_exam_session_subjects" ess
JOIN "acted"."catalog_exam_sessions" es ON es.id = ess.exam_session_id
GROUP BY es.session_code
ORDER BY es.session_code;
